System.register([],function(e,c){var t,a,o,n;return{setters:[],execute:function(){a=(e,c,t,a,o,n)=>({id:e,type:"dialogue",speaker:c,speakerKey:t,text:a,sprite:o?{key:o,position:"linmo"===o?"left":"right"}:void 0,effects:n}),o=(e,c,t,a,o)=>({id:e,type:"quiz",text:c,quiz:t,onCorrect:a,onWrong:o,speaker:""}),n=(e,c)=>({id:e,type:"system",text:c,speaker:""}),e("chapter6Script",[(t=(e,c,t)=>({id:e,type:"narration",text:c,speaker:"",background:t}))("ch6-0-0","第6章：表观遗传\n\n第5章加速衰老结束后第三天。你面前摆着两份DNA甲基化测序数据——一份是你自己的，一份是张总的。","office"),a("ch6-0-1","林雪","linxue","你们俩的DNA甲基化模式——在衰老后变化几乎相同。但有一个关键差异：MT-ND5基因上游的启动子区域——在你的细胞里——衰老后去甲基化了。在张总的细胞里——同一个区域超甲基化了。","linxue"),o("ch6-0-2","林雪指向屏幕上CpG岛的甲基化热图。",{question:"DNA甲基化通常发生在什么二核苷酸序列上？启动子CpG岛超甲基化对基因表达有什么影响？",options:[{label:"A",text:"CpG二核苷酸；启动子超甲基化→MBD蛋白募集→HDAC→染色质压缩→基因转录沉默",correct:!0},{label:"B",text:"ApT二核苷酸；超甲基化激活转录",correct:!1},{label:"C",text:"GpC二核苷酸；不影响转录",correct:!1},{label:"D",text:"任何G都行；随机影响",correct:!1}],explanation:"哺乳动物DNA甲基化主要发生在CpG二核苷酸的胞嘧啶第5位碳(5mC)。DNMT(DNA甲基转移酶)催化甲基化；TET双加氧酶催化去甲基化(5mC→5hmC→5fC→5caC→切除修复)。启动子CpG岛超甲基化→MBD蛋白→HDAC→组蛋白去乙酰化→染色质压缩→转录因子无法结合→基因沉默。",knowledgeId:"dna_methylation",knowledgeTitle:"DNA甲基化——CpG岛、DNMT与TET"},[a("ch6-0-2c","林雪","linxue","你的衰老激活了ND5——张总的衰老关闭了ND5。这就是为什么你是完美适配体——他不是。你父亲设计了一个只有当孩子面临生命危险时才会激活的表观遗传开关。","linxue",{affection:{linxue:10}})],[a("ch6-0-2w","林雪","linxue","CpG——胞嘧啶-磷酸-鸟嘌呤。DNMT催化甲基化。TET催化去甲基化。启动子甲基化=关闭基因。","linxue")]),t("ch6-1-0","小雅的工位。三个屏幕同时显示着ChIP-seq数据——组蛋白修饰的全基因组热图。","office"),a("ch6-1-1","小雅","xiaoya","H3K27ac——组蛋白H3第27位赖氨酸乙酰化——在ND5启动子区域——增加了3.2倍！H3K27me3——三甲基化——在同一区域——减少到几乎检测不到！","xiaoya"),o("ch6-1-2","小雅把组蛋白密码速查表投影在屏幕上。",{question:"H3K27ac和H3K27me3分别代表什么状态的染色质？为什么它们互斥？",options:[{label:"A",text:"H3K27ac=活性染色质(增强子/启动子活跃)；H3K27me3=抑制性染色质(Polycomb沉默)；两者在同一残基上互斥",correct:!0},{label:"B",text:"两者都是激活标记",correct:!1},{label:"C",text:"两者都是抑制标记",correct:!1},{label:"D",text:"H3K27ac抑制，H3K27me3激活",correct:!1}],explanation:'H3K27ac由组蛋白乙酰转移酶(HAT, CBP/p300)催化→活性增强子/启动子。H3K27me3由PRC2(Polycomb抑制复合体2, EZH2催化)催化→基因沉默。两者在同一个赖氨酸残基上不能共存——这是一个精密的"开关"：乙酰化=ON，三甲基化=OFF。这种切换是细胞命运决定的表观遗传基础。',knowledgeId:"histone_code",knowledgeTitle:"组蛋白密码——H3K27ac(ON) vs H3K27me3(OFF)"},[a("ch6-1-2c","小雅","xiaoya","对！乙酰化=开，甲基化=关。你的ND5从关变成了开——因为衰老触发了去甲基化+乙酰化。你父亲用了一个自然界最优雅的双保险开关。","xiaoya",{affection:{xiaoya:10}})],[a("ch6-1-2w","小雅","xiaoya","H3K27ac=乙酰化=活性=启动子开启。H3K27me3=三甲基化=抑制=关闭。同一个残基，两种修饰——互斥！","xiaoya")]),t("ch6-2-0","B2层DNA分析室。苏菲亚放大21号染色体长臂——加速衰老前后对比——出现了一个新的插入序列。","dna_storage"),a("ch6-2-1","苏菲亚","sophia","LINE-1。长散在核元件。一种逆转录转座子。在加速衰老的72小时内——它动了。从原来的位置——转录出RNA——逆转录成DNA——插入到了新的基因组位置。","sophia"),o("ch6-2-2","苏菲亚指着LINE-1的ORF2结构域。",{question:"LINE-1逆转录转座子利用什么酶活性进行转座？",options:[{label:"A",text:"ORF2蛋白——同时具有逆转录酶和内切酶活性——自我催化转座",correct:!0},{label:"B",text:"转座酶",correct:!1},{label:"C",text:"DNA聚合酶",correct:!1},{label:"D",text:"整合酶",correct:!1}],explanation:"LINE-1(约6kb)占人类基因组17%。ORF1=RNA结合蛋白；ORF2=逆转录酶+内切酶。转座：RNA转录→ORF2切开DNA→以L1 RNA为模板逆转录→插入新位点。正常细胞中LINE-1被DNA甲基化+H3K9me3严密沉默。衰老→表观遗传抑制减弱→LINE-1活化→基因组不稳定性增加。",knowledgeId:"line1_transposon",knowledgeTitle:'LINE-1逆转录转座子——衰老中的"跳跃基因"'},[a("ch6-2-2c","苏菲亚","sophia",'LINE-1插入了SIRT1——长寿基因——破坏了它。你的父亲在QZ-1中加入了维持DNMT1活性的信号——所以你的转座子压制得比正常人好得多。他还是帮你把"墙"筑得更高。',"sophia",{affection:{sophia:10}})],[a("ch6-2-2w","苏菲亚","sophia",'LINE-1——ORF2同时有逆转录酶和内切酶活性。约17%的人类基因组来自LINE-1。衰老中它被"唤醒"——到处跳跃——破坏基因。',"sophia")]),t("ch6-3-0","王博士的办公室。书架上全是代谢通路的旧书。桌上放着三样东西：一瓶叶酸片、一瓶维生素B12、一张一碳单位代谢通路图。","office"),a("ch6-3-1","王博士","wang",'你父亲说的"甲基钥匙"——不是比喻。是字面意思。丝氨酸→THF→5-甲基-THF。B12将甲基转移到同型半胱氨酸→甲硫氨酸→SAM。SAM是体内最重要的活性甲基供体——DNMT用它来甲基化DNA。',"wang"),o("ch6-3-2","王博士在MT-ND5启动子第-127位CpG上画了一个圈。",{question:"一碳单位的主要载体是什么？活性甲基的直接供体是什么？",options:[{label:"A",text:"四氢叶酸(THF)；S-腺苷甲硫氨酸(SAM)",correct:!0},{label:"B",text:"维生素B12；ATP",correct:!1},{label:"C",text:"NADPH；乙酰CoA",correct:!1},{label:"D",text:"SAM；THF",correct:!1}],explanation:"THF(四氢叶酸)是一碳单位载体——从丝氨酸/甘氨酸/组氨酸/色氨酸接收一碳单位(甲基/亚甲基/次甲基/甲酰基/亚氨甲基)。SAM(S-腺苷甲硫氨酸)是体内最重要的活性甲基供体——用于DNA甲基化、神经递质合成等。叶酸→DHFR→THF；B12将甲基从5-甲基-THF转移到同型半胱氨酸→甲硫氨酸→SAM。",knowledgeId:"one_carbon_sam",knowledgeTitle:"一碳单位代谢——THF载体，SAM活性甲基供体"},[a("ch6-3-2c","王博士","wang",'这个甲基——MT-ND5启动子第-127位CpG——就是你父亲说的"钥匙"。把它放回去——关掉ND5——关掉完美适配体——轮回终止。或者——合成反向酶——修改QZ-酶的别构位点让它不再识别ND5。两条路——殊途同归。',"wang",{affection:{wang:15}})],[a("ch6-3-2w","王博士","wang","THF——四氢叶酸——一碳单位载体。SAM——S-腺苷甲硫氨酸——活性甲基供体。叶酸→THF；B12转移甲基。记住这个通路。","wang")]),t("ch6-4-0","小雅突然跳起来——撞到了桌上的葡萄糖果冻。","office"),a("ch6-4-1","小雅","xiaoya","这不就是lac操纵子吗！！虽然人是真核生物没有操纵子——但原理是一样的！乳糖操纵子：CAP-cAMP→激活，LacI阻遏蛋白→抑制。MT-ND5启动子：TET去甲基化+H3K27ac→激活，DNMT重新甲基化+H3K27me3→抑制。双保险开关！","xiaoya"),o("ch6-4-2","小雅兴奋地在空气中画出lac操纵子的结构。",{question:"乳糖操纵子在什么条件下被高效转录？",options:[{label:"A",text:"有乳糖(异乳糖解除LacI阻遏)+无葡萄糖(cAMP↑→CAP-cAMP激活)——两个条件缺一不可",correct:!0},{label:"B",text:"只有乳糖存在就够",correct:!1},{label:"C",text:"有葡萄糖、无乳糖",correct:!1},{label:"D",text:"任何条件下都被激活",correct:!1}],explanation:"lac操纵子双重调控：(1)负调控——LacI阻遏蛋白无乳糖时结合操纵基因(O)阻断转录；乳糖→异乳糖与LacI→构象变化→解离→去抑制。(2)正调控——CAP在cAMP存在时结合启动子上游CAP位点，促进RNA聚合酶结合。葡萄糖→cAMP↓→CAP不结合→即使LacI解离，转录效率也很低。双保险：去抑制+正激活。",knowledgeId:"lac_operon_review",knowledgeTitle:"lac操纵子——双重调控（去抑制+正激活）"},[a("ch6-4-2c","小雅","xiaoya","你父亲在你的DNA里设计了一个比任何人类工程都精巧的双保险开关。他不是科学家——他是分子雕刻家。","xiaoya",{affection:{xiaoya:10}})],[a("ch6-4-2w","小雅","xiaoya","lac操纵子双保险：乳糖存在=去抑制 + 葡萄糖缺乏=CAP-cAMP正激活。两个条件都要满足——就像你的ND5开关。","xiaoya")]),n("ch6-end",'▎第6章完成：表观遗传\n\n▎新增知识条目：DNA甲基化(CpG/DNMT/TET) | 组蛋白密码(H3K27ac/H3K27me3) | LINE-1逆转录转座子 | 一碳单位/SAM | lac操纵子复习\n▎关键发现：甲基钥匙 = MT-ND5启动子第-127位CpG\n▎两条路：重新甲基化关闭ND5 | 合成反向酶修改QZ-酶别构位点\n▎SAN值：+5（希望——衰老可以被擦除）\n\n▎第7-8章终章预告\n"所有的碎片该拼起来了。反向抑制酶——谁来合成它？谁来注射它？谁来终结这轮回？"')])}}});